+// =============================================================================
+// Build Helpers
+// =============================================================================
+// These helper functions reduce boilerplate for adding test/benchmark executables.
+// Usage example:
+//   const exe = addMetalTestExe(b, target, optimize, "test-foo", "src/test_foo.zig");
+//   addTestStep(b, exe, "test-foo", "Description of test");
+
+/// Configuration for test executables
+pub const TestExeConfig = struct {
+    /// Link Metal GPU frameworks (Metal, Foundation, MetalKit)
+    metal: bool = true,
+    /// Link Accelerate framework (BLAS, vDSP)
+    accelerate: bool = true,
+    /// Link C++ standard library
+    libcpp: bool = true,
+    /// Accept command line arguments
+    accepts_args: bool = true,
+};
+
+/// Add a test executable with Metal frameworks linked
+pub fn addMetalTestExe(
+    b: *std.Build,
+    target: std.Build.ResolvedTarget,
+    optimize: std.builtin.OptimizeMode,
+    name: []const u8,
+    source: []const u8,
+) *std.Build.Step.Compile {
+    return addTestExeWithConfig(b, target, optimize, name, source, .{});
+}
+
+/// Add a test executable with custom configuration
+pub fn addTestExeWithConfig(
+    b: *std.Build,
+    target: std.Build.ResolvedTarget,
+    optimize: std.builtin.OptimizeMode,
+    name: []const u8,
+    source: []const u8,
+    config: TestExeConfig,
+) *std.Build.Step.Compile {
+    const exe = b.addExecutable(.{
+        .name = name,
+        .root_module = b.createModule(.{
+            .root_source_file = b.path(source),
+            .target = target,
+            .optimize = optimize,
+        }),
+    });
+
+    if (config.metal) {
+        exe.root_module.linkFramework("Metal", .{});
+        exe.root_module.linkFramework("Foundation", .{});
+        exe.root_module.linkFramework("MetalKit", .{});
+    }
+
+    if (config.accelerate) {
+        exe.root_module.linkFramework("Accelerate", .{});
+    }
+
+    if (config.libcpp) {
+        exe.linkLibCpp();
+    }
+
+    exe.linkLibC();
+    b.installArtifact(exe);
+
+    return exe;
+}
+
+/// Add a run step for a test executable
+pub fn addTestStep(
+    b: *std.Build,
+    exe: *std.Build.Step.Compile,
+    step_name: []const u8,
+    description: []const u8,
+    accepts_args: bool,
+) *std.Build.Step {
+    const run = b.addRunArtifact(exe);
+    run.step.dependOn(b.getInstallStep());
+
+    if (accepts_args) {
+        if (b.args) |args| {
+            run.addArgs(args);
+        }
+    }
+
+    const step = b.step(step_name, description);
+    step.dependOn(&run.step);
+    return step;
+}
